import{_ as t,o as e,c as l,ag as i}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Other/PCB笔记.md","filePath":"Other/PCB笔记.md","lastUpdated":1775898880000}'),a={name:"Other/PCB笔记.md"};function r(_,p,o,s,n,C){return e(),l("div",null,[...p[0]||(p[0]=[i("<p>PCB绘制流程：</p><ol><li>创建原理图库和PCB库，完成封装和元件对应</li><li>检查PCB库和原理图库是否有误，三遍原则</li><li>按照信号的流向绘制原理图</li><li>编译检查原理图，三遍</li><li>将原理图导入PCB并调整布局</li><li>设置规则，编译检查PCB绘制是否有误</li></ol><p>放光二极管原理图，正极是A负极是K。同一型号原件在设计绘制原理图时在工具中选择新部件创建多part部件。</p><p>引脚要放置在格点商，引脚长度与网格设置为100mil放置引脚，10mil绘制器件原型，100mil绘制原理图。VGS调格栅</p><p>设计-&gt;生成原理图库</p><p>报告-&gt;中间检查原理图库的问题</p><p>拖动状态下按XY可以上下左右镜像，空格进行旋转。</p><p>选中按A可以选择对齐方式</p><p>CTRL+W原理图布线，shift+空格布斜线。</p><p>14.连线较多的时候可以将要连接的信号线设置成网络标签</p><p>15.工具-&gt;标注-&gt;原理图标注 将绘制好的原理图使用的器件进行标号</p><p>16.ctrl+F进行元器件的查找，J+C跳转到元器件的位置</p><p>17.点击工程右键对原理图进行编译，找到原理图的问题</p><p>18.报告-&gt;bill中导出物料表</p><p>19.文件中导出原理图</p><p>20.找到选项点击+CTRL自定义快捷键</p><p>24.报告里检查原理图库和封装库</p><p>25.放置里找绘制3D封装的选项，绘制3D封装要绘制在机械层上</p><p>26.PCB导入报错，检查封装是否缺失，名称是否错误，管脚号是否对应正确</p><p>27.可以外部导入DXF文件来绘制板型，工具-转换-B进行板子挖孔</p><p>30.设计里层叠管理器添加多层，添加两种层——正偏层和负偏层，正偏层画上的导线都是铜，负偏层默认都是铜画上线的位置没有铜</p><p>31.PCB和原理图右键进行分割式布局然后在工具中打开交叉选择模式，模块化布局：工具-模块摆放-在矩形区域排列 设置快捷键使用</p>",22)])])}const B=t(a,[["render",r]]);export{c as __pageData,B as default};
